export class BaseService {
  protected config: Config;
  constructor(config: Config) { this.config = config; }
}

export class HttpService extends BaseService {
  protected httpClient: HttpClient;
  constructor(config: Config, client: HttpClient) {
    super(config);
    this.httpClient = client;
  }
}

export class MessagesService extends HttpService {
  private transformer: MessageTransformer;
  constructor(config: Config, client: HttpClient, xform: MessageTransformer) {
    super(config, client);
    this.transformer = xform;
  }
}
